# Pseudocode — adapt to your IAM platform (Okta, Azure AD, Ping Identity)
class AttestationAccessGate:
    """Enforces that active, unexpired attestation is required for Claude-adjacent entitlements."""

    def __init__(self, iam_client, attestation_db):
        self.iam = iam_client
        self.db = attestation_db

    def grant_entitlement_if_attested(self, user_id: str, entitlement: str) -> dict:
        record = self.db.get_latest(user_id)
        if not record or record["status"] != "active":
            return {"granted": False, "reason": "no_active_attestation"}
        if record["policy_version"] != self.db.current_policy_version():
            return {"granted": False, "reason": "stale_policy_version"}
        # Grant in IAM
        self.iam.add_entitlement(user_id, entitlement, expires=record["expires_at"])
        return {"granted": True, "entitlement": entitlement, "expires": record["expires_at"]}

    def revoke_on_expiry(self, user_id: str) -> list[str]:
        """Called by a nightly job or expiry webhook."""
        revoked = []
        for ent in self.iam.list_entitlements(user_id, tag="aup_gated"):
            self.iam.remove_entitlement(user_id, ent)
            revoked.append(ent)
        return revoked
